// MARK: - Session Row

/// A session row with icon and flat list styling
struct SessionRow: View {
    @Environment(\.colorScheme) private var colorScheme
    @Environment(AppState.self) private var appState

    let session: Session
    let isSelected: Bool
    var onSelect: () -> Void
    var onCreateTerminalTab: (() -> Void)?
    var onArchive: (() -> Void)?
    var onRename: ((String) -> Void)?
    var onDelete: (() -> Void)?

    @State private var isHovered = false
    @State private var showArchiveConfirmation = false
    @State private var showDeleteConfirmation = false
    @State private var showRenameDialog = false
    @State private var renameTitle = ""

    private var colors: ThemeColors {
        ThemeColors(colorScheme)
    }

    private var runtimeStatus: CodingSessionRuntimeStatus? {
        appState.sessionRuntimeStatusService.runtimeStatusBySessionId[session.id]?.codingSession.status
    }

    private var shouldShowSpinner: Bool {
        guard let runtimeStatus else { return false }
        return runtimeStatus == .running || runtimeStatus == .waiting
    }

    var body: some View {
        let _ = appState.sessionRuntimeStatusService.runtimeStatusBySessionId
        Button(action: onSelect) {
            HStack(spacing: Spacing.sm) {
                Group {
                    if shouldShowSpinner {
                        ProgressView()
                            .controlSize(.mini)
                            .tint(isSelected ? colors.primary : colors.gray525)
                    } else {
                        Image(systemName: "message.fill")
                            .font(.system(size: 12))
                            .foregroundStyle(isSelected ? colors.primary : colors.gray525)
                    }
                }
                .frame(width: 12, height: 12)

                Text(session.displayTitle)
                    .font(Typography.caption)
                    .foregroundStyle(isSelected ? colors.sidebarText : colors.sidebarMeta)
                    .lineLimit(1)

                Spacer()
            }
            .padding(.leading, LayoutMetrics.sidebarInset)
            .padding(.trailing, Spacing.sm)
            .frame(height: LayoutMetrics.sidebarRowHeight)
            .fullRowHitTarget()
            .background(
                RoundedRectangle(cornerRadius: Radius.lg)
                    .fill(isSelected ? colors.hoverBackground : (isHovered ? colors.hoverBackground : Color.clear))
            )
            .overlay(
                RoundedRectangle(cornerRadius: Radius.lg)
                    .stroke(isSelected ? colors.selectionBorder : Color.clear, lineWidth: BorderWidth.hairline)
            )
        }
        .buttonStyle(.plain)
        .onHover { hovering in
            isHovered = hovering
        }
        .contextMenu {
            if onRename != nil {
                Button {
                    renameTitle = session.displayTitle
                    showRenameDialog = true
                } label: {
                    Label("Rename...", systemImage: "pencil")
                }

                Divider()
            }

            if onCreateTerminalTab != nil {
                Button {
                    onCreateTerminalTab?()
                } label: {
                    Label("New Terminal Tab", systemImage: "terminal")
                }

                Divider()
            }

            Button {
                showArchiveConfirmation = true
            } label: {
                Label("Archive", systemImage: "archivebox")
            }

            Divider()

            Button {
                showDeleteConfirmation = true
            } label: {
                Label("Delete", systemImage: "trash")
            }
        }
        .confirmationDialog(
            "Archive Session?",
            isPresented: $showArchiveConfirmation,
            titleVisibility: .visible
        ) {
            Button("Archive") {
                onArchive?()
            }
            Button("Cancel", role: .cancel) {}
        } message: {
            Text("This session will be moved to the archived section.")
        }
        .confirmationDialog(
            "Delete Session?",
            isPresented: $showDeleteConfirmation,
            titleVisibility: .visible
        ) {
            Button("Delete") {
                onDelete?()
            }
            Button("Cancel", role: .cancel) {}
        } message: {
            Text("This action cannot be undone. All messages in this session will be permanently deleted.")
        }
        .sheet(isPresented: $showRenameDialog) {
            RenameSessionSheet(initialTitle: renameTitle) { newTitle in
                onRename?(newTitle)
            }
        }
    }
}

private struct RenameSessionSheet: View {
    @Environment(\.dismiss) private var dismiss
    @State private var title: String
    let onSave: (String) -> Void

    init(initialTitle: String, onSave: @escaping (String) -> Void) {
        _title = State(initialValue: initialTitle)
        self.onSave = onSave
    }

    private var trimmedTitle: String {
        title.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    var body: some View {
        VStack(alignment: .leading, spacing: Spacing.md) {
            Text("Rename Session")
                .font(Typography.body)

            TextField("Session title", text: $title)
                .textFieldStyle(.roundedBorder)
                .onSubmit {
                    handleSave()
                }

            HStack {
                Spacer()
                Button("Cancel") {
                    dismiss()
                }
                Button("Save") {
                    handleSave()
                }
                .keyboardShortcut(.defaultAction)
                .disabled(trimmedTitle.isEmpty)
            }
        }
        .padding(Spacing.md)
        .frame(minWidth: 320)
    }

    private func handleSave() {
        let newTitle = trimmedTitle
        guard !newTitle.isEmpty else { return }
        onSave(newTitle)
        dismiss()
    }
}

